PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "migrations" ("id" integer primary key autoincrement not null, "migration" varchar not null, "batch" integer not null);
CREATE TABLE IF NOT EXISTS "password_reset_tokens" ("email" varchar not null, "token" varchar not null, "created_at" datetime, primary key ("email"));
CREATE TABLE IF NOT EXISTS "sessions" ("id" varchar not null, "user_id" integer, "ip_address" varchar, "user_agent" text, "payload" text not null, "last_activity" integer not null, primary key ("id"));
CREATE TABLE IF NOT EXISTS "cache" ("key" varchar not null, "value" text not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "cache_locks" ("key" varchar not null, "owner" varchar not null, "expiration" integer not null, primary key ("key"));
CREATE TABLE IF NOT EXISTS "jobs" ("id" integer primary key autoincrement not null, "queue" varchar not null, "payload" text not null, "attempts" integer not null, "reserved_at" integer, "available_at" integer not null, "created_at" integer not null);
CREATE TABLE IF NOT EXISTS "job_batches" ("id" varchar not null, "name" varchar not null, "total_jobs" integer not null, "pending_jobs" integer not null, "failed_jobs" integer not null, "failed_job_ids" text not null, "options" text, "cancelled_at" integer, "created_at" integer not null, "finished_at" integer, primary key ("id"));
CREATE TABLE IF NOT EXISTS "failed_jobs" ("id" integer primary key autoincrement not null, "uuid" varchar not null, "connection" text not null, "queue" text not null, "payload" text not null, "exception" text not null, "failed_at" datetime not null default CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS "configuracion" ("id" integer primary key autoincrement not null, "nombre_empresa" varchar, "direccion_empresa" varchar, "telefono_empresa" varchar, "movil_empresa" varchar, "email" varchar, "nif_cif" varchar, "metatitulo" varchar, "metadescripcion" varchar, "g_analytics" varchar, "url" varchar, "youtube" varchar, "google_plus" varchar, "instagram" varchar, "twitter" varchar, "facebook" varchar, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "tipo_contenidos" ("id" integer primary key autoincrement not null, "tipo_contenido" varchar, "icono" varchar, "created_at" datetime, "updated_at" datetime, "descripcion" varchar);
CREATE TABLE IF NOT EXISTS "galerias" ("id" integer primary key autoincrement not null, "carpeta" varchar, "orden" integer, "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "image_configs" ("id" integer primary key autoincrement not null, "tipo_contenido" varchar not null, "tipo_imagen" varchar not null, "ancho" integer not null, "alto" integer not null, "mantener_aspecto" tinyint(1) not null default '1', "formato" varchar not null default 'jpg', "calidad" integer not null default '85', "redimensionar" tinyint(1) not null default '1', "activo" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime, "ancho_movil" integer, "alto_movil" integer, "mantener_aspecto_movil" tinyint(1) not null default '1', "calidad_movil" integer not null default '85', "generar_version_movil" tinyint(1) not null default '1', "descripcion" varchar);
CREATE TABLE IF NOT EXISTS "gallery_images" ("id" integer primary key autoincrement not null, "gallery_id" integer not null, "titulo" varchar, "descripcion" text, "imagen" varchar not null, "imagen_miniatura" varchar, "alt_text" varchar, "orden" integer not null default '0', "activa" tinyint(1) not null default '1', "metadatos" text, "created_at" datetime, "updated_at" datetime, foreign key("gallery_id") references "galleries"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "galleries" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "descripcion" text, "activa" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "contents" ("id" integer primary key autoincrement not null, "lugar" varchar, "fecha" date, "fecha_publicacion" date, "tipo_contenido" varchar check ("tipo_contenido" in ('pagina', 'noticia', 'entrevista', 'galeria')) not null default 'noticia', "imagen" varchar, "imagen_portada" varchar, "pagina_estatica" tinyint(1) not null default ('0'), "columnas" integer not null default ('1'), "fb_pixel" text, "portada" tinyint(1) not null default ('0'), "galeria_id" integer, "actions" varchar, "orden" integer, "created_at" datetime, "updated_at" datetime, "imagen_alt" text, "imagen_portada_alt" text, foreign key("galeria_id") references "galleries"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "idiomas" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "etiqueta" varchar not null, "imagen" varchar, "activo" tinyint(1) not null default '1', "es_principal" tinyint(1) not null default '0', "orden" integer not null default '0', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "gallery_image_texts" ("id" integer primary key autoincrement not null, "gallery_image_id" integer not null, "idioma_id" integer not null, "titulo" varchar, "descripcion" text, "alt_text" varchar, "created_at" datetime, "updated_at" datetime, foreign key("gallery_image_id") references "gallery_images"("id") on delete cascade, foreign key("idioma_id") references "idiomas"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "menus" ("id" integer primary key autoincrement not null, "parent_id" integer, "content_id" integer, "url" text, "icon" varchar, "menu_pie" tinyint(1) not null default ('0'), "created_at" datetime, "updated_at" datetime, "tipo_enlace" varchar not null default ('contenido'), "tipo_contenido_id" integer, "visible" tinyint(1) not null default ('1'), "abrir_nueva_ventana" tinyint(1) not null default ('0'), "orden" integer not null default ('1'), "url_externa" varchar, foreign key("content_id") references contents("id") on delete set null on update no action, foreign key("parent_id") references menus("id") on delete cascade on update no action, foreign key("tipo_contenido_id") references "tipo_contenidos"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "slide_translations" ("id" integer primary key autoincrement not null, "slide_id" integer not null, "idioma_id" integer not null, "titulo" varchar not null, "descripcion" text, "alt_text" varchar, "url" varchar, "created_at" datetime, "updated_at" datetime, foreign key("slide_id") references "slides"("id") on delete cascade, foreign key("idioma_id") references "idiomas"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "slides" ("id" integer primary key autoincrement not null, "created_at" datetime, "updated_at" datetime, "nueva_ventana" tinyint(1) not null default ('0'), "imagen" varchar, "imagen_miniatura" varchar, "metadatos" text, "visible" tinyint(1) not null default ('1'), "orden" integer, "activo" tinyint(1) not null default ('1'));
CREATE TABLE IF NOT EXISTS "roles" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "slug" varchar not null, "descripcion" text, "activo" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "permissions" ("id" integer primary key autoincrement not null, "nombre" varchar not null, "slug" varchar not null, "modulo" varchar not null, "tipo_permiso" varchar check ("tipo_permiso" in ('crear', 'mostrar', 'editar', 'eliminar')) not null, "descripcion" text, "activo" tinyint(1) not null default '1', "created_at" datetime, "updated_at" datetime);
CREATE TABLE IF NOT EXISTS "role_permissions" ("id" integer primary key autoincrement not null, "role_id" integer not null, "permission_id" integer not null, "created_at" datetime, "updated_at" datetime, foreign key("role_id") references "roles"("id") on delete cascade, foreign key("permission_id") references "permissions"("id") on delete cascade);
CREATE TABLE IF NOT EXISTS "users" ("id" integer primary key autoincrement not null, "name" varchar not null, "email" varchar not null, "email_verified_at" datetime, "password" varchar not null, "remember_token" varchar, "created_at" datetime, "updated_at" datetime, "role_id" integer, foreign key("role_id") references "roles"("id") on delete set null);
CREATE TABLE IF NOT EXISTS "configuracion_empresa" ("id" integer primary key autoincrement not null, "nombre" varchar, "direccion" varchar, "telefono" varchar, "email" varchar, "redes_sociales" text, "created_at" datetime, "updated_at" datetime, "metatitulo" varchar, "metadescripcion" text, "metatitulo_es" varchar, "metadescripcion_es" text, "metatitulo_ast" varchar, "metadescripcion_ast" text, "metatitulo_en" varchar, "metadescripcion_en" text);
CREATE TABLE textos_idiomas (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                idioma_id INTEGER NOT NULL,
                contenido_id INTEGER,
                tipo_contenido_id INTEGER NULL,
                titulo VARCHAR(255) NULL,
                subtitulo VARCHAR(255) NULL,
                resumen VARCHAR(255) NULL,
                contenido TEXT NULL,
                metadescripcion TEXT NULL,
                metatitulo TEXT NULL,
                slug VARCHAR(191) NULL,
                visible BOOLEAN DEFAULT 1,
                imagen_alt TEXT NULL,
                imagen_portada_alt TEXT NULL,
                objeto_type VARCHAR(255) NULL,
                objeto_id INTEGER NULL,
                campo VARCHAR(255) NULL,
                texto TEXT NULL,
                activo BOOLEAN DEFAULT 1,
                created_at DATETIME NULL,
                updated_at DATETIME NULL
            );
DELETE FROM sqlite_sequence;
CREATE INDEX "sessions_user_id_index" on "sessions" ("user_id");
CREATE INDEX "sessions_last_activity_index" on "sessions" ("last_activity");
CREATE INDEX "jobs_queue_index" on "jobs" ("queue");
CREATE UNIQUE INDEX "failed_jobs_uuid_unique" on "failed_jobs" ("uuid");
CREATE UNIQUE INDEX "image_configs_tipo_contenido_tipo_imagen_unique" on "image_configs" ("tipo_contenido", "tipo_imagen");
CREATE INDEX "gallery_images_gallery_id_orden_index" on "gallery_images" ("gallery_id", "orden");
CREATE INDEX "gallery_images_gallery_id_activa_index" on "gallery_images" ("gallery_id", "activa");
CREATE INDEX "idiomas_new_activo_index" on "idiomas" ("activo");
CREATE INDEX "idiomas_new_es_principal_index" on "idiomas" ("es_principal");
CREATE INDEX "idiomas_new_orden_index" on "idiomas" ("orden");
CREATE UNIQUE INDEX "idiomas_new_etiqueta_unique" on "idiomas" ("etiqueta");
CREATE INDEX "gallery_image_texts_gallery_image_id_idioma_id_index" on "gallery_image_texts" ("gallery_image_id", "idioma_id");
CREATE UNIQUE INDEX "unique_gallery_image_idioma" on "gallery_image_texts" ("gallery_image_id", "idioma_id");
CREATE UNIQUE INDEX "slide_translations_slide_id_idioma_id_unique" on "slide_translations" ("slide_id", "idioma_id");
CREATE INDEX "slide_translations_slide_id_idioma_id_index" on "slide_translations" ("slide_id", "idioma_id");
CREATE INDEX "slide_translations_titulo_index" on "slide_translations" ("titulo");
CREATE INDEX "slides_orden_index" on "slides" ("orden");
CREATE INDEX "slides_visible_activo_orden_index" on "slides" ("visible", "activo", "orden");
CREATE UNIQUE INDEX "roles_slug_unique" on "roles" ("slug");
CREATE INDEX "permissions_modulo_tipo_permiso_index" on "permissions" ("modulo", "tipo_permiso");
CREATE UNIQUE INDEX "permissions_unique_module_type" on "permissions" ("modulo", "tipo_permiso", "slug");
CREATE UNIQUE INDEX "permissions_slug_unique" on "permissions" ("slug");
CREATE UNIQUE INDEX "role_permissions_role_id_permission_id_unique" on "role_permissions" ("role_id", "permission_id");
CREATE UNIQUE INDEX "users_email_unique" on "users" ("email");
COMMIT;
