INSERT INTO textos_idiomas VALUES(60,3,16,1,'Bienvenidos Y Bienvenidas','Web De Producciones Nun Tris','<p>En activo desde 1992, y como profesional desde 1997. M&aacute;s de<strong> 50 espect&aacute;culos estrenados.</strong></p>',replace(replace('<p>La versatilidad en cuanto a estilos y p&uacute;blicos, y la capacidad de afrontar retos art&iacute;sticos es lo que mejor puede definir nuestro transitar por la escena asturiana.</p>\r\n<p>Por supuesto, aspectos como la formaci&oacute;n cont&iacute;nua o las colaboraciones con profesionales cualificados son fundamentales para conseguir estos resultados al cabo del tiempo. Nuestra intenci&oacute;n es seguir ofreciendo espect&aacute;culos de todas clases, para todo tipo de p&uacute;blico, sin olvidar la b&uacute;squeda de nuevos rumbos para lo que puede llamarse Teatro Asturiano con denominaci&oacute;n de origen la formaci&oacute;n, o la investigaci&oacute;n sobre formas contempor&aacute;neas.</p>\r\n<p>En esta p&aacute;gina se puede encontrar informaci&oacute;n sobre la compa&ntilde;&iacute;a, nuestros trabajos y proyectos, y las novedades en cuanto a la actividad que desarrollamos</p>','\r',char(13)),'\n',char(10)),'we de producciones nuntris, nueva web','Producciones nuntris','presentacion',1,'web de produciones nuntris','web de produciones nuntris',NULL,NULL,NULL,NULL,1,'2025-11-13 16:41:27','2025-11-18 15:47:28');
